from lxml import etree

def process_soap_request(xml_data):
    # Define a DTD parser
    dtd_parser = etree.DTD('path/to/your/dtd_file.dtd')
    
    # Parse the XML data with the DTD
    try:
        root = etree.fromstring(xml_data, parser=etree.XMLParser(load_dtd=True))
        if not dtd_parser.validate(root):
            raise ValueError("DTD validation failed")
        
        # Extract the SOAP envelope and body
        soap_envelope = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
        soap_body = soap_envelope.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
        
        if soap_body is None:
            raise ValueError("SOAP Body not found in the request")
        
        # Further processing of the SOAP body can be done here
        return soap_body
        
    except etree.XMLSyntaxError as e:
        print(f"XML Syntax Error: {e}")
    except ValueError as e:
        print(f"Value Error: {e}")

